import os
import sys
import json
import time
import asyncio

# Add backend to path
sys.path.append(os.path.join(os.path.dirname(os.path.dirname(__file__)), "backend"))

from app.services.blockchain import get_blockchain_connection, get_sponsor_wallet
from thor_requests.contract import Contract

BYTECODE = ""

async def main():
    print("Connecting to VeChain Testnet RPC...")
    conn = get_blockchain_connection()
    
    # We will use the platform sponsor wallet (which is funded) to deploy the contract
    deployer_wallet = get_sponsor_wallet()
    if not deployer_wallet:
        print("Error: Sponsor wallet not configured in env.")
        return
        
    print(f"Deployer Wallet Address: {deployer_wallet.getAddress()}")
    
    # Check balance
    balance = conn.get_vtho_balance(deployer_wallet.getAddress())
    print(f"Deployer VTHO balance: {balance / 1e18:.2f} VTHO")
    
    if balance < 1e18:
         print("Error: Deployer wallet does not have enough VTHO (energy) for deployment.")
         return
         
    # Define registry contract
    contract = Contract({
        "abi": [], # bytecode deployment doesn't strictly need the ABI during deploy() call
        "bytecode": bytes.fromhex(BYTECODE)
    })
    
    print("Broadcasting deployment transaction to VeChain...")
    try:
        tx_receipt = conn.deploy(
            wallet=deployer_wallet,
            contract=contract
        )
        tx_id = tx_receipt.get("id") or tx_receipt.get("meta", {}).get("txID")
        print(f"✔ Deployment transaction sent! TxID: {tx_id}")
        
        print("Waiting for transaction to be mined (this takes about 10 seconds)...")
        receipt = conn.wait_for_tx_receipt(tx_id, timeout=30)
        
        if not receipt:
            print("Timeout waiting for receipt.")
            return
            
        if receipt.get("reverted"):
            print("❌ Deployment transaction reverted!")
            return
            
        # Get deployed contract address from output receipt
        outputs = receipt.get("outputs", [])
        if outputs:
            contract_address = outputs[0].get("contractAddress")
            print(f"\n🎉 SUCCESS! DesignRegistry deployed to: {contract_address}")
            print("Use this address for your settings!")
        else:
             print("No contract address found in transaction outputs.")
             
    except Exception as e:
        print(f"❌ Deployment failed: {e}")

if __name__ == "__main__":
    asyncio.run(main())
